/* ============================================================
   OnyxFox - sidebery-amoled.css
   Paste into Sidebery: Settings -> Styles editor -> Sidebar.
   (Or import sidebery/onyxfox.sidebery.json for one click.)
   https://github.com/balakumardev/onyxfox  (MIT)
   Inspired by VerticalFox (github.com/christorange/VerticalFox),
   rebuilt for Sidebery v5.5.2 / Firefox 151.

   Set Sidebery Color scheme = dark FIRST, or these colors revert.
   Collapsed frame = 44px, expanded (hover) = 260px.
   Titles hidden < 120px, shown >= 120px (keep in sync with userChrome.css).
   ============================================================ */

/* ---------- AMOLED COLOR SYSTEM ---------- */
#root.root {
  --s-frame-bg:#000; --s-frame-fg:#e6e6e6;
  --s-toolbar-bg:#000; --s-toolbar-fg:#e6e6e6; --s-toolbar-border:#1a1a1a;
  --s-popup-bg:#0a0a0a; --s-popup-fg:#e6e6e6; --s-popup-border:#1f1f1f;
  --s-act-el-bg:#111; --s-act-el-fg:#fff; --s-act-el-border:#222; --s-accent:#4aa3ff;
  --tabs-normal-bg:#000; --tabs-normal-fg:#cfcfcf;
  --tabs-activated-bg:#111; --tabs-activated-fg:#fff;
  --frame-el-overlay-hover-bg:#1a1a1a; --frame-el-overlay-clicked-bg:#222;
  --frame-el-overlay-selected-bg:#1e1e1e;
  --ctx-menu-bg:#0a0a0a; --ctx-menu-fg:#e6e6e6;
  --scroll-color:#2a2a2a; --popup-scrollbar-color:#2a2a2a; --toolbar-scrollbar-color:#2a2a2a; --frame-scrollbar-color:#2a2a2a;
}
#root {
  --frame-bg:#000 !important; --toolbar-bg:#000 !important; --bg:#000 !important;
  --tabs-fg:#cfcfcf !important; --tabs-bg-hover:#1a1a1a !important; --tabs-activated-bg:#111 !important;
  --tabs-height:33px; --tabs-pinned-height:var(--tabs-height);
}

/* ---------- BASE TAB STYLING (always on) ---------- */
.Tab { margin:auto; width:98%; border-radius:4px; }
.Tab .lvl-wrapper:after { display:none; }
.Tab .title { overflow:hidden !important; transition:margin-left 300ms ease; }
.Tab .close > svg:hover { border-radius:3px; background:#8c4351 !important; opacity:.8; }
.Tab:hover { --tabs-inner-gap:8px; }
.Tab:hover .title { margin-left:8px; }
.Tab[data-discarded="true"] .title { opacity:.7; }

/* ---------- PINNED TABS (v5.5.2: .Tab[data-pin="true"]) ---------- */
.PinnedTabsBar { background-color:#000 !important; }
.Tab[data-pin="true"] { margin:5px 0 4px 6px; border-radius:4px; }

/* ---------- NAV BAR ---------- */
.NavigationBar { background-color:#000 !important; }
.NavigationBar .nav-item:hover { border-radius:4px !important; background-color:#1a1a1a !important; }
.NavigationBar .nav-item[data-active="true"] { border-radius:4px !important; background-color:#111 !important; }

/* ============================================================
   COLLAPSED RAIL (frame < 120px ≈ your 44px)
   ============================================================ */
@media (max-width: 120px) {
  #root:not(:hover) .Tab { --tabs-indent:-1000px; }
  .Tab[data-lvl] > div.lvl-wrapper { right:-2px; }
  .Tab { max-width:40px; }
  .Tab .body { justify-content:center; }
  .Tab[data-pin="false"] .fav { margin:0 !important; }
  .Tab .fav { z-index:1; }
  .Tab .t-box, .Tab .title { display:none !important; }   /* clean rail */
  .Tab .close { display:none !important; }
  .Tab .audio { z-index:1; margin-left:-12px; height:26px; }
  .Tab[data-pin="true"] { margin-left:5px; }
  .NavigationBar .nav-item[data-type="settings"] { display:none; }
}

/* ---------- EXPANDED ---------- */
.Tab .body { align-items:center; }

/* ---------- IDLE micro-adjustments ---------- */
#root:not(:hover) .Tab .audio { top:-10px; left:26px; transform:scale(.8); transition:top .2s ease-in-out; }
#root:hover .Tab .audio { top:0; transition:top .2s ease-in-out; }
#root:not(:hover) .Tab .fav-icon { left:2px; }

/* ---------- BOTTOM NAV: collapse to single centered item when idle ---------- */
#nav_bar .nav-item { opacity:0; transition:opacity .7s cubic-bezier(.42,0,.58,1); }
#nav_bar .nav-item:first-child { opacity:1; }
#root:hover #nav_bar .nav-item { opacity:1; transition-delay:.05s; }
#root:not(:hover) #nav_bar .nav-item { opacity:0; transition:opacity .5s ease-in-out; transition-delay:.05s; }
#root:not(:hover) #nav_bar .nav-item[data-active="true"] {
  opacity:1; position:absolute; left:45%; transform:translateX(-50%);
  transition:left .3s ease-in-out, transform .3s ease-in-out;
}
#root:not(:hover) .static-btns,
#root:not(:hover) .Notifications,
#root:not(:hover) .BottomBar .tool-btn:not(:first-child) { display:none; }
#root:not(:hover) .BottomBar { display:flex; justify-content:center; }
#root:not(:hover) .BottomBar .tool-btn:first-child { margin:0 auto; }

/* Soft scroll shadows */
.ScrollBox > .top-shadow[data-show="true"],
.ScrollBox > .bottom-shadow[data-show="true"] { opacity:.5; }
